using System.Collections.Generic;\nusing Microsoft.AspNetCore.Mvc;\n\nnamespace TheWorldGame.Controllers\n{\n    [ApiController]\n    [Route("api/[controller]")]\n    public class TradeController : ControllerBase\n    {\n        private List<Trade> tradeHistory = new List<Trade>();\n\n        [HttpPost("buy")]\n        public IActionResult Buy([FromBody] Trade trade)\n        {\n            // Implement buy logic\n            // Add trade to history\n            tradeHistory.Add(trade);\n            return Ok(trade);\n        }\n\n        [HttpPost("sell")]\n        public IActionResult Sell([FromBody] Trade trade)\n        {\n            // Implement sell logic\n            // Add trade to history\n            tradeHistory.Add(trade);\n            return Ok(trade);\n        }\n\n        [HttpPost("validate")]\n        public IActionResult Validate([FromBody] Trade trade)\n        {\n            // Implement validation logic\n            return Ok(new { valid = true });\n        }\n\n        [HttpGet("history")]\n        public IActionResult GetTradeHistory()\n        {\n            return Ok(tradeHistory);\n        }\n    }\n\n    public class Trade\n    {\n        public string Type { get; set; } // Buy or Sell\n        public decimal Amount { get; set; }\n        public string Currency { get; set; }\n        public string User { get; set; }\n        public DateTime Timestamp { get; set; } = DateTime.UtcNow;\n    }\n}